export async function getAllQuestions(){
    const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/questions`)
    const data = await response.json()
    return data

}
export async function submitAnswer(surveyID: number, answers: Record<number,number>, additionalAnswer?: string){

    const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/surveys/submit-answer`,{
        method: 'POST',
        headers: {
            'Content-Type': 'application/json'
        },
        body: JSON.stringify({
            surveyID,
            answers,
            additionalAnswer
        })
    })
    const data = await response.json()
    return data
}
